window.__NEWS = {"now": 1782803508, "data": [{"title": "SpaceX officially prices shares at $135 in the largest IPO ever", "detail": "n/9691490157c1.html", "url": "https://techcrunch.com/2026/06/11/spacex-officially-prices-shares-at-135-in-the-largest-ipo-ever/", "theme": "business", "score": 102, "level": "medium", "sources": 7, "players": ["SpaceX"], "ago": 1593518, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/13/openai-faces-investigation-from-state-attorneys-general/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/policy/949970/ai-regulation-child-safety-kosa-congress"}, {"label": "AI Explained", "href": "https://www.youtube.com/watch?v=aJvP3nXWkwM"}, {"label": "Two Minute Papers", "href": "https://www.youtube.com/watch?v=ypL7kUiw_LM"}, {"label": "OpenAI", "href": "https://www.youtube.com/watch?v=NxAxwsu6_Zs"}, {"label": "Anthropic (Claude)", "href": "https://www.youtube.com/watch?v=N4efO8viXXo"}, {"label": "Inteligencia Artificial (ES)", "href": "https://www.youtube.com/watch?v=jE-O6N7-MLA"}], "sum": "SpaceX has priced its shares at $135 each, raising $75 billion in what is now the largest IPO in history, surpassing Saudi Aramco's previous record. This unusual pricing strategy, set ahead of the traditional roadshow, attracted significant interest from investors, indicating strong demand. The implications for investors and the market are substantial, as this IPO not only positions Elon Musk as a potential trillionaire but also raises questions about how SpaceX will sustain its high valuation amid ambitious engineering projects."}, {"title": "From data to decisions: how LSEG is scaling trusted AI", "detail": "n/ee9a377ec782.html", "url": "https://www.youtube.com/watch?v=sU9-u5p-jA0", "theme": "business", "score": 83, "level": "medium", "sources": 3, "players": ["OpenAI"], "ago": 1522021, "urls": [{"label": "OpenAI", "href": "https://www.youtube.com/watch?v=sU9-u5p-jA0"}, {"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/22/the-ai-world-is-getting-loopy/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/tech/952104/adobe-firefly-ai-agent-elements-projects-update"}], "sum": "LSEG is enhancing its AI capabilities by integrating trusted data services with OpenAI's technology, allowing for faster decision-making in financial markets. The company has reduced its product release cycle from several months to bi-weekly, which accelerates the delivery of AI-driven insights. This shift is significant as it enables analysts to focus on deeper research and insights, potentially transforming how financial data is utilized."}, {"title": "DeepSeek V4 AI Beats Billion Dollar Systems…For Free", "detail": "n/e65cf201ca27.html", "url": "https://www.youtube.com/watch?v=p7K3xfViWCE", "theme": "other", "score": 83, "level": "medium", "sources": 3, "players": ["DeepSeek"], "ago": 4719834, "urls": [{"label": "Two Minute Papers", "href": "https://www.youtube.com/watch?v=zJvN8PDX1is"}, {"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/16/probably-raises-9m-to-build-a-more-reliable-kind-of-ai/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/952011/midjourney-medical-ai-ultrasound-scan"}], "sum": "DeepSeek V4 has been released as a free AI model that reportedly matches the performance of billion-dollar systems, featuring a one million token context window and advanced compression techniques. This development is significant as it democratizes access to high-performance AI, potentially lowering costs for users and reshaping the competitive landscape. However, limitations exist, including its unimodal nature and challenges with context limits, which users should be aware of."}, {"title": "Ford had to hire back former engineers to fix mistakes made by its automated systems", "detail": "n/91da026df123.html", "url": "https://www.theverge.com/transportation/956316/ford-quality-jd-power-ranking-ai-automated-mistakes", "theme": "business", "score": 80, "level": "medium", "sources": 2, "players": [], "ago": 414708, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/transportation/956316/ford-quality-jd-power-ranking-ai-automated-mistakes"}, {"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/28/ford-rehires-gray-beard-engineers-after-ai-falls-short/"}], "sum": "Ford has regained the top spot in JD Power’s initial quality ranking after addressing significant issues with its automated systems. The company had to rehire over 350 experienced engineers to correct errors caused by AI reliance, which had previously led to a decline in vehicle quality. This situation underscores the importance of institutional knowledge and proactive quality management in manufacturing, particularly in the automotive sector."}, {"title": "World leaders want American AI. They just don’t want America to be able to turn it off.", "detail": "n/b626f5f34b3e.html", "url": "https://techcrunch.com/2026/06/17/world-leaders-want-american-ai-they-just-dont-want-america-to-be-able-to-turn-it-off/", "theme": "other", "score": 80, "level": "medium", "sources": 2, "players": [], "ago": 1080629, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/27/asian-ai-startups-launch-mythos-like-models-as-anthropics-export-ban-drags-on/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/column/951516/trump-anthropic-feud-mythos-fable-white-house"}], "sum": "At the G7 Summit, leaders expressed concerns over the U.S. ability to restrict access to American AI models, as demonstrated by the recent blocking of Anthropic's models. This situation highlights the vulnerability of countries relying on U.S. AI infrastructure, which could be revoked without warning. The implications are significant for international companies and governments, as they must now consider the risks to their economic security and technological sovereignty."}, {"title": "Figma adds code layers, support for animations, more AI features in new update", "detail": "n/b15a0f3d4939.html", "url": "https://techcrunch.com/2026/06/24/figma-adds-code-layers-support-for-animations-more-ai-features-in-new-update/", "theme": "features", "score": 76, "level": "medium", "sources": 2, "players": [], "ago": 485808, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/24/figma-adds-code-layers-support-for-animations-more-ai-features-in-new-update/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/tech/955831/figma-code-design-tools-config-2026-announcements"}], "sum": "Figma has introduced an update that integrates code layers, supports animations, and enhances AI capabilities within its design platform. This update allows designers and developers to collaborate more effectively by enabling direct code integration and the creation of custom plugins. The implications for users include improved workflow efficiency and the potential for more innovative design iterations without the need for pristine code."}, {"title": "Google bets on Gemini to reinvent the smart home speaker", "detail": "n/116c37f23c0c.html", "url": "https://techcrunch.com/2026/06/17/google-bets-on-gemini-to-reinvent-the-smart-home-speaker/", "theme": "features", "score": 76, "level": "medium", "sources": 2, "players": ["Google"], "ago": 1089699, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/17/google-bets-on-gemini-to-reinvent-the-smart-home-speaker/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/gadgets/955537/google-home-smart-speaker-hands-on"}], "sum": "Google has launched the Google Home Speaker, its first audio device designed specifically for its Gemini AI, priced at $99.99. This new speaker allows for natural language requests and multi-step commands, enhancing user interaction compared to previous models. The introduction of a subscription plan for advanced features may create a new revenue stream, but its success will depend on user willingness to pay for these capabilities."}, {"title": "Collecting robot training data is dirty, unglamorous work. Some AI labs are already paying XDOF to do it.", "detail": "n/84378f271cdd.html", "url": "https://techcrunch.com/2026/06/17/collecting-robot-training-data-is-dirty-unglamorous-work-some-ai-labs-are-already-paying-xdof-to-do-it/", "theme": "business", "score": 76, "level": "medium", "sources": 2, "players": [], "ago": 1095108, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/22/openai-launches-new-initiative-to-help-find-and-patch-open-source-bugs/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/955939/openai-reveals-its-first-ai-processor-jalapeno"}], "sum": "XDOF has emerged to address the critical shortage of high-quality training data for robotics, a gap highlighted by OpenAI's recent relaunch of its robotics program. The startup has raised $70 million to build data pipelines and annotation systems essential for teaching robots to interact with the physical world. This development is significant as it indicates a shift in focus towards the infrastructure needed for robotics, which could accelerate advancements in the field and prevent leading AI labs from falling behind."}, {"title": "What Happens After A 1,000,000x AI Compute Leap? | Jeff Dean", "detail": "n/3b1cdfb32f76.html", "url": "https://www.youtube.com/watch?v=yz6I23VRbdg", "theme": "insights", "score": 76, "level": "medium", "sources": 2, "players": [], "ago": 2475026, "urls": [{"label": "Two Minute Papers", "href": "https://www.youtube.com/watch?v=yz6I23VRbdg"}, {"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/22/google-deepmind-bets-75m-on-ais-future-in-hollywood-with-a24-deal/"}], "sum": "In a recent interview, Jeff Dean, Google's chief scientist, discussed the future of AI compute, emphasizing that while concerns about running out of training data persist, there are still abundant resources available, including video data and synthetic data generation. He highlighted the shift from training to inference in data centers, which now accounts for 90% of workloads, necessitating a redesign of hardware to optimize for inference tasks. This shift is crucial for businesses as it indicates a need for more efficient and specialized computing resources to handle increasing demands for AI applications."}, {"title": "South Korean tech giants commit over $550B to ease ‘RAMageddon’", "detail": "n/5442c22415cc.html", "url": "https://techcrunch.com/2026/06/29/south-korean-tech-giants-commit-over-550b-to-ease-ramageddon/", "theme": "business", "score": 75, "level": "high", "sources": 1, "players": [], "ago": 47040, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/29/south-korean-tech-giants-commit-over-550b-to-ease-ramageddon/"}], "sum": "South Korea's major tech companies, led by Samsung and SK Hynix, have pledged over $550 billion to expand memory chip production and AI infrastructure. This investment aims to address the global shortage of memory chips, termed 'RAMageddon', driven by increasing AI demands. The initiative is crucial for South Korea's ambition to enhance its position in the global semiconductor and AI markets, but execution risks remain due to the long timelines associated with building semiconductor fabs."}, {"title": "Anthropic’s Claude is winning over paid consumers, a market owned by ChatGPT", "detail": "n/c24c53ef5b17.html", "url": "https://techcrunch.com/2026/06/25/anthropics-claude-is-winning-over-paid-consumers-a-market-owned-by-chatgpt/", "theme": "business", "score": 75, "level": "medium", "sources": 2, "players": ["OpenAI", "Anthropic"], "ago": 394401, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/25/the-white-house-is-asking-openai-to-slow-roll-the-release-of-its-new-model-over-safety-concerns/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/957372/openai-will-delay-gpt-5-6-after-trump-administration-request"}], "sum": "Anthropic's Claude has seen a significant increase in paid consumer adoption, with a reported 75% growth since January 2026. This trend, highlighted by credit card transaction data, indicates a shift in consumer preference despite ChatGPT's dominant market position. The implications for businesses are clear: as Claude gains traction, companies may need to reassess their AI strategies and consider diversifying their offerings to include Claude alongside ChatGPT."}, {"title": "Facebook rolls out an AI companion app for creators", "detail": "n/b7024825b20c.html", "url": "https://techcrunch.com/2026/06/24/facebook-rolls-out-an-ai-companion-app-for-creators/", "theme": "tools", "score": 75, "level": "medium", "sources": 2, "players": ["Meta"], "ago": 482124, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/24/facebook-rolls-out-an-ai-companion-app-for-creators/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/tech/956668/meta-facebook-creator-studio-ai-app-relaunch"}], "sum": "Facebook has launched a standalone AI companion app aimed at helping creators grow their audiences on the platform. This move is part of Meta's strategy to retain creators amidst competition from TikTok and YouTube, while also reducing reliance on third-party tools. The app features an AI assistant that provides personalized recommendations and insights, which could enhance user engagement and streamline content management for creators."}, {"title": "As AI agents become employees, NewCore emerges with $66M to give them identities", "detail": "n/bf4c56821442.html", "url": "https://techcrunch.com/2026/06/15/ai-agents-are-becoming-employees-newcore-emerges-with-66m-to-give-them-identities/", "theme": "business", "score": 75, "level": "medium", "sources": 2, "players": [], "ago": 1275108, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/15/ai-agents-are-becoming-employees-newcore-emerges-with-66m-to-give-them-identities/"}, {"label": "OpenAI", "href": "https://www.youtube.com/watch?v=-Jm-Bf3g9r8"}], "sum": "NewCore, a cybersecurity startup, has raised $66 million to address the challenges of managing AI agents as they become integral to the workforce. The company aims to provide a platform that treats AI agents as first-class identities, essential for enterprise security. This development is significant as organizations increasingly deploy AI agents, necessitating robust identity management systems to prevent security vulnerabilities."}, {"title": "Deezer’s new tool can identify AI music from Spotify, Apple Music, and others", "detail": "n/4f9aae068b78.html", "url": "https://techcrunch.com/2026/06/11/deezers-new-tool-can-identify-ai-music-from-spotify-apple-music-and-others/", "theme": "tools", "score": 75, "level": "medium", "sources": 2, "players": ["Apple"], "ago": 1607728, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/17/pinterest-launches-an-experimental-ai-shopping-app-called-ask-pinterest/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/953183/the-atlantic-searchable-database-music-ai-training-data"}], "sum": "Deezer has launched a free online tool that scans playlists from various streaming platforms to identify AI-generated music. This move addresses growing concerns about copyright issues and potential fraud related to AI music. By actively removing AI tracks from recommendations, Deezer positions itself as a leader in transparency within the music streaming industry, potentially attracting consumers who prioritize authenticity in their music choices."}, {"title": "Lawmakers want to ban AI companies from selling your health data", "detail": "n/97835e796bb3.html", "url": "https://www.theverge.com/ai-artificial-intelligence/959033/health-location-data-protection-act-ai-warren-scanlon", "theme": "other", "score": 73, "level": "medium", "sources": 1, "players": [], "ago": 54708, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/959033/health-location-data-protection-act-ai-warren-scanlon"}], "sum": "A new proposal led by Senator Elizabeth Warren aims to prohibit the sale of Americans' health and location data to data brokers, including information shared with AI chatbots. This updated Health and Location Data Protection Act seeks to address privacy concerns as AI companies increasingly handle sensitive health information. The bill would empower the FTC to enforce these regulations, highlighting the urgent need for stronger data protection in the AI era."}, {"title": "The fittest founder in the room got cancer. Here’s how he used AI to fight back.", "detail": "n/65b970247eab.html", "url": "https://techcrunch.com/2026/06/27/the-fittest-founder-in-the-room-got-cancer-heres-how-he-used-ai-to-fight-back/", "theme": "cases", "score": 73, "level": "medium", "sources": 1, "players": [], "ago": 234708, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/27/the-fittest-founder-in-the-room-got-cancer-heres-how-he-used-ai-to-fight-back/"}], "sum": "Conno Christou, a health-conscious entrepreneur, was diagnosed with aggressive non-Hodgkin’s lymphoma after a routine checkup. By leveraging AI tools and gathering multiple medical opinions, he navigated his treatment effectively, opting for a more aggressive chemotherapy regimen that significantly improved his chances of recovery. This case illustrates the potential of AI in personal healthcare decision-making, emphasizing the importance of proactive patient engagement in medical treatment."}, {"title": "The $27 million Al proxy war over Alex Bores ends in a draw", "detail": "n/9670f0f233eb.html", "url": "https://www.theverge.com/ai-artificial-intelligence/956263/alex-bores-new-york-12th-district-congressional-primary-results", "theme": "business", "score": 73, "level": "medium", "sources": 2, "players": [], "ago": 481608, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/18/ai-data-centers-just-got-a-government-mandated-fast-lane-to-the-grid/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/952180/amazon-seattle-data-center-moratorium-aecj-disciplinary-action"}], "sum": "The Democratic primary for New York's 12th Congressional District concluded with Alex Bores losing to Micah Lasher, marking the end of a $27 million political battle influenced by major AI companies Anthropic and OpenAI. Bores, known for his advocacy of AI safety through the RAISE Act, faced significant opposition from a pro-AI super PAC. This outcome highlights the growing intersection of technology and politics, particularly as AI regulation becomes a contentious issue in electoral campaigns."}, {"title": "The Problem Solvers | Michael Truell at Cursor", "detail": "n/e82cf2ee9a9b.html", "url": "https://www.youtube.com/watch?v=8NVZMRyCrn4", "theme": "business", "score": 73, "level": "medium", "sources": 1, "players": ["Anthropic"], "ago": 1696277, "urls": [{"label": "Anthropic (Claude)", "href": "https://www.youtube.com/watch?v=8NVZMRyCrn4"}], "sum": "Cursor, a software development tool leveraging AI, has rapidly grown from a small team to 700 employees, now serving over 60% of the Fortune 500. This growth reflects a significant shift in the software industry, enabling both professional engineers and non-engineers to build applications more efficiently. The partnership with Anthropic has been pivotal, aligning Cursor's product development with advancements in AI modeling, which could reshape how software is created and deployed."}, {"title": "General Intuition’s $2.3B bet that video games can train AI agents for the real world", "detail": "n/560980794f80.html", "url": "https://techcrunch.com/2026/06/25/general-intuitions-2-3b-bet-that-video-games-can-train-ai-agents-for-the-real-world/", "theme": "business", "score": 72, "level": "high", "sources": 1, "players": [], "ago": 397008, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/25/general-intuitions-2-3b-bet-that-video-games-can-train-ai-agents-for-the-real-world/"}], "sum": "General Intuition has raised $320 million at a $2.3 billion valuation to develop AI agents that learn from video game data, aiming to create models that can operate in both virtual and real-world environments. This approach leverages gameplay data to enhance AI's spatial-temporal reasoning, potentially offering a scalable alternative to traditional data collection methods. The implications for industries relying on AI are significant, as this technology could streamline the training of agents for various applications, from robotics to simulation."}, {"title": "Patronus AI lands $50M to build ‘digital worlds’ that stress-test AI agents", "detail": "n/26550eb8ca32.html", "url": "https://techcrunch.com/2026/06/25/patronus-ai-lands-50m-to-build-digital-worlds-that-stress-test-ai-agents/", "theme": "business", "score": 72, "level": "medium", "sources": 1, "players": [], "ago": 384743, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/25/patronus-ai-lands-50m-to-build-digital-worlds-that-stress-test-ai-agents/"}], "sum": "Patronus AI has secured $50 million in Series B funding to develop simulated digital environments for stress-testing AI agents. This funding reflects a significant demand from AI labs for reliable evaluation methods, as traditional benchmarks fail to ensure real-world task performance. The startup's revenue has surged 15-fold in the past year, indicating strong market interest and potential for growth in AI reliability solutions."}, {"title": "DOJ claims xAI’s unpermitted gas turbines are a matter of ‘national, economic, and energy security’", "detail": "n/500b9c34e8da.html", "url": "https://techcrunch.com/2026/06/16/doj-claims-xais-unpermitted-gas-turbines-are-a-matter-of-national-economic-and-energy-security/", "theme": "business", "score": 71, "level": "medium", "sources": 2, "players": ["xAI"], "ago": 1181205, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/16/doj-claims-xais-unpermitted-gas-turbines-are-a-matter-of-national-economic-and-energy-security/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/958751/prosecutors-chatgpt-palisades-wildfire-arson-mistrial"}], "sum": "The Department of Justice has sided with xAI in a lawsuit regarding the company's use of unpermitted natural gas turbines near its Memphis data centers. The DOJ argues that halting this operation could jeopardize national security and military operations reliant on AI. This situation highlights the tension between environmental regulations and the demands of technological advancement, raising concerns about air quality and public health in an already polluted region."}, {"title": "The Fitbit Air takes a smarter approach to the AI health dumpster fire", "detail": "n/18ab8a77858b.html", "url": "https://www.theverge.com/tech/954768/google-fitbit-air-review-fitness-tracker-wearable-ai-health-coach", "theme": "tools", "score": 70, "level": "medium", "sources": 2, "players": ["Google"], "ago": 576708, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/21/beyond-siri-here-are-the-practical-ai-features-coming-to-your-iphone-in-ios-27/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/tech/949360/apple-ai-photo-edit-reframe-extend-clean-up-hands-on"}], "sum": "The Google Fitbit Air, priced at $99, introduces an AI health coach that offers personalized fitness insights based on user data. While the hardware is lightweight and has excellent battery life, the effectiveness of the AI coach depends heavily on user engagement and input. This matters as it reflects a shift in consumer health technology towards more interactive and tailored experiences, though it raises questions about the reliability and necessity of AI in personal health management."}, {"title": "Nvidia's New Cooling System and Its Limitations on Water Usage", "detail": "n/746439952901.html", "url": "https://techcrunch.com/2026/06/22/nvidia-wants-to-cut-data-center-water-use-but-thats-not-the-same-as-fixing-ais-water-problem/", "theme": "business", "score": 70, "level": "medium", "sources": 2, "players": ["NVIDIA"], "ago": 644613, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/22/nvidia-wants-to-cut-data-center-water-use-but-thats-not-the-same-as-fixing-ais-water-problem/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/tech/954139/nvidia-data-centers-rubin-liquid-cooling"}], "sum": "Nvidia has introduced a warm-water cooling system aimed at significantly reducing water usage in data centers, claiming it can eliminate nearly all on-site water consumption. However, this solution only addresses a fraction of the total water footprint, as it does not account for water used in electricity generation and chip manufacturing, which can double or triple overall consumption. The reliance on fossil fuels for power generation remains a critical issue, as these plants are major water consumers, undermining Nvidia's water-saving claims."}, {"title": "Only 16 percent of Americans think AI will have a positive impact on society, a new study shows", "detail": "n/6e25bb08cb18.html", "url": "https://techcrunch.com/2026/06/17/only-16-percent-of-americans-think-ai-will-have-a-positive-impact-on-society-a-new-study-shows/", "theme": "other", "score": 70, "level": "medium", "sources": 2, "players": [], "ago": 1087907, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/17/only-16-percent-of-americans-think-ai-will-have-a-positive-impact-on-society-a-new-study-shows/"}, {"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/951653/pew-research-ai-chatbot-usage-advancing-too-quickly"}], "sum": "A Pew Research study reveals that only 16% of Americans believe AI will positively impact society over the next 20 years, with 40% expecting negative effects. The study highlights a significant skepticism towards government regulation and corporate responsibility in AI development. This sentiment is particularly strong among younger individuals, with only 14% of those under 30 viewing AI positively. The implications suggest a growing divide between AI usage and public trust, which could hinder future adoption and regulatory efforts."}, {"title": "Databricks’ former AI chief thinks he can cut AI’s power bill by 1,000x", "detail": "n/9986e4db05a4.html", "url": "https://techcrunch.com/2026/06/25/databricks-former-ai-chief-thinks-he-can-cut-ais-power-bill-by-1000x/", "theme": "models", "score": 68, "level": "high", "sources": 1, "players": [], "ago": 397417, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/25/databricks-former-ai-chief-thinks-he-can-cut-ais-power-bill-by-1000x/"}], "sum": "Unconventional AI, led by former Databricks AI chief Naveen Rao, aims to revolutionize computing architecture with a new oscillator-based design that could reduce AI's power consumption by up to 1000 times. The company has launched its first model, Un0, which demonstrates the potential of this technology in image generation. This development is significant as it addresses the impending energy limitations that could hinder AI scalability in the future, making it a critical innovation for the industry."}, {"title": "Base44 launches own AI model to enhance app creation capabilities", "detail": "n/534a67ec1d1b.html", "url": "https://techcrunch.com/2026/06/29/vibe-coding-platform-base44-launches-own-model-as-ai-startups-seek-defensibility/", "theme": "business", "score": 68, "level": "medium", "sources": 1, "players": [], "ago": 16987, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/29/vibe-coding-platform-base44-launches-own-model-as-ai-startups-seek-defensibility/"}], "sum": "Base44, a vibe coding platform recently acquired by Wix, has launched its own AI model, Base1, to support app creation using natural language. This move addresses concerns about the long-term defensibility of businesses relying on external models, as Base44 aims to optimize performance and reduce costs. The development of Base1, trained on extensive user interaction data, positions Base44 to compete more effectively against both vibe coding startups and established AI labs, potentially improving its market standing and profitability."}, {"title": "China’s Z.ai claims it can match Mythos on cybersecurity", "detail": "n/5d43e7e568e3.html", "url": "https://www.theverge.com/ai-artificial-intelligence/958804/chinas-z-ai-glm-52-mythos-cybersecurity", "theme": "models", "score": 68, "level": "medium", "sources": 1, "players": ["Anthropic"], "ago": 120537, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/958804/chinas-z-ai-glm-52-mythos-cybersecurity"}], "sum": "China's Zhipu AI has released the GLM-5.2 model, which reportedly matches Mythos in specific cybersecurity tasks, particularly bug-finding. This advancement narrows the gap between Chinese AI capabilities and those of leading US models from companies like Anthropic and OpenAI. The implications are significant for national security, as the US government has been actively working to limit China's access to advanced AI technologies."}, {"title": "Former Infosys chief has a new startup that wants to challenge the IT services world", "detail": "n/a9be7fc515fd.html", "url": "https://techcrunch.com/2026/06/24/former-infosys-chief-has-a-new-startup-that-wants-to-challenge-the-it-services-world/", "theme": "business", "score": 68, "level": "medium", "sources": 1, "players": [], "ago": 459896, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/24/former-infosys-chief-has-a-new-startup-that-wants-to-challenge-the-it-services-world/"}], "sum": "Vishal Sikka, former CEO of Infosys, has launched a new startup, Hang Ten Systems, which has raised $32 million to leverage AI for IT services traditionally handled by human workers. This move is significant as it signals a potential shift in the IT services industry, where firms are grappling with how AI could disrupt traditional business models. As enterprises increasingly seek AI-driven solutions, Hang Ten's approach may redefine software development and delivery, impacting how IT services firms operate."}, {"title": "AI was supposed to kill engineering jobs, but new data suggests they’re the most resilient", "detail": "n/6c7367eab768.html", "url": "https://techcrunch.com/2026/06/24/ai-was-supposed-to-kill-engineering-jobs-but-new-data-suggests-theyre-the-most-resilient/", "theme": "insights", "score": 68, "level": "medium", "sources": 1, "players": [], "ago": 465307, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/24/ai-was-supposed-to-kill-engineering-jobs-but-new-data-suggests-theyre-the-most-resilient/"}], "sum": "Recent data from SignalFire indicates that engineering jobs are more resilient than previously thought, despite fears of AI-driven automation. While tech layoffs have surged, engineering roles saw only an 11% decline in hiring compared to 2019, with engineers making up 55% of new hires in major tech firms. This suggests that rather than replacing engineers, AI tools are enhancing their productivity, leading to increased demand for engineering talent."}, {"title": "World model maker Odyssey nabs $1.45B valuation backed by Amazon and other big names", "detail": "n/289b12dac76c.html", "url": "https://techcrunch.com/2026/06/17/world-model-maker-odyssey-nabs-1-45b-valuation-backed-by-amazon-and-other-big-names/", "theme": "business", "score": 68, "level": "medium", "sources": 1, "players": ["Amazon"], "ago": 1085321, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/18/general-intuition-in-talks-to-raise-300m-at-around-2b-valuation/"}], "sum": "Odyssey, an AI startup specializing in world models, has achieved a $1.45 billion valuation following a $310 million Series B funding round led by Natural Capital, with participation from Amazon and others. This funding underscores the growing importance of world models in AI, which simulate real-world data for applications ranging from gaming to robotics. The backing from Amazon positions Odyssey to leverage AWS infrastructure, potentially enhancing its competitive edge in the AI market."}, {"title": "A satellite just learned to find things on its own — here’s what that means", "detail": "n/3df362228dbf.html", "url": "https://techcrunch.com/2026/06/15/a-satellite-just-learned-to-find-things-on-its-own-heres-what-that-means/", "theme": "other", "score": 68, "level": "medium", "sources": 1, "players": [], "ago": 1278708, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/15/a-satellite-just-learned-to-find-things-on-its-own-heres-what-that-means/"}], "sum": "An Earth observation satellite, YAM-9, successfully identified areas of interest autonomously using a vision-language model (VLM) developed by NASA's Jet Propulsion Laboratory. This milestone indicates a shift in how space-based sensors can operate, potentially reducing the data overload for human analysts and enhancing the utility of satellite data. The implications extend to future AI applications in space, paving the way for real-time monitoring and advanced scientific tools."}, {"title": "Pushing Large Models to the Limit to Connect All Human Knowledge", "detail": "n/4cb946190d81.html", "url": "https://www.youtube.com/watch?v=7uQaPvTphsY", "theme": "other", "score": 68, "level": "medium", "sources": 1, "players": [], "ago": 1602692, "urls": [{"label": "Inteligencia Artificial (ES)", "href": "https://www.youtube.com/watch?v=7uQaPvTphsY"}], "sum": "Elisenda Bow, co-founder of an AI startup acquired by Apple, discusses the evolution of AI and the importance of reliable data in model training. She emphasizes the need for AI systems to not only access vast knowledge but also ensure the validity of the information they provide. This matters because as AI becomes more integrated into daily life, the accuracy and trustworthiness of its outputs will significantly impact decision-making processes for individuals and businesses alike."}, {"title": "The memory chip crunch is paying off for this US company", "detail": "n/5805b4628162.html", "url": "https://techcrunch.com/2026/06/24/the-memory-chip-crunch-is-paying-off-for-this-u-s-company/", "theme": "business", "score": 67, "level": "high", "sources": 1, "players": [], "ago": 466853, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/24/the-memory-chip-crunch-is-paying-off-for-this-u-s-company/"}], "sum": "Micron Technology has significantly benefited from the ongoing shortage of memory chips, driven by increased demand from AI applications. The company's stock surged over 13% following a report of a quadrupling in revenue to $41.45 billion and a profit increase to $28.2 billion year-over-year. This financial success highlights the critical role of memory chips in the tech industry and suggests that companies involved in this sector may continue to see substantial growth as demand persists."}, {"title": "The AI jobs debate just got messier", "detail": "n/3c82ab124c4b.html", "url": "https://techcrunch.com/2026/06/29/the-ai-jobs-debate-just-got-messier/", "theme": "insights", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 11448, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/29/the-ai-jobs-debate-just-got-messier/"}], "sum": "Concerns about AI-related job losses are intensifying, with nearly 90,000 layoffs linked to AI announced by May 2026. However, a report from Ramp and Revelio Labs indicates that companies investing heavily in AI are actually increasing their workforce, particularly in entry-level positions. This suggests that while AI may not universally create jobs, it can facilitate firm expansion, particularly among tech-forward companies, potentially widening the gap between resource-rich firms and those struggling to adapt."}, {"title": "Gemini’s personalized AI image generation is now free for US users", "detail": "n/5b59cc183adb.html", "url": "https://techcrunch.com/2026/06/29/geminis-personalized-ai-image-generation-is-now-free-for-u-s-users/", "theme": "features", "score": 67, "level": "medium", "sources": 1, "players": ["Google"], "ago": 39529, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/29/geminis-personalized-ai-image-generation-is-now-free-for-u-s-users/"}], "sum": "Google has made its Gemini app's personalized image generation feature available for free to all eligible users in the U.S., expanding access beyond previous paid tiers. This feature leverages user data from various Google services to create images that reflect individual preferences without explicit prompts. The move is significant as it could increase user engagement and solidify Gemini's competitive position in the AI landscape, particularly as it has already surpassed 750 million monthly active users."}, {"title": "Robot hand company settles Tesla trade secret suit and announces $11M raise", "detail": "n/4a54fd56cc74.html", "url": "https://techcrunch.com/2026/06/29/robot-hand-company-settles-tesla-trade-secret-suit-and-announces-11m-raise/", "theme": "business", "score": 67, "level": "medium", "sources": 1, "players": ["Tesla"], "ago": 61900, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/29/robot-hand-company-settles-tesla-trade-secret-suit-and-announces-11m-raise/"}], "sum": "Proception, a robotics startup founded by former Tesla employee Jay Li, has settled a trade secret lawsuit with Tesla and secured an $11 million seed funding round. This funding, led by First Round Capital, will support Proception's development of high-dexterity robotic hands aimed at mimicking human manipulation. The implications for the robotics industry are significant, as advancements in dexterous manipulation could accelerate the deployment of humanoid robots in various applications."}, {"title": "Omen AI’s plan to optimize data centers is all wet", "detail": "n/132af78715f3.html", "url": "https://techcrunch.com/2026/06/29/omen-ais-plan-to-optimize-data-centers-is-all-wet/", "theme": "business", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 65508, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/29/omen-ais-plan-to-optimize-data-centers-is-all-wet/"}], "sum": "Omen AI has raised $31 million in Series A funding to develop a spectrometer that monitors the health of cooling fluids in data centers, addressing bacterial contamination that can lead to costly downtime. This innovation is crucial as data centers increasingly rely on liquid cooling to manage heat from GPUs. By providing real-time insights, Omen aims to prevent significant operational disruptions and enhance efficiency in a sector that is becoming more reliant on advanced monitoring technologies."}, {"title": "Netris raises $15M Series A from a16z to help AI neoclouds go live faster", "detail": "n/31294c2cb197.html", "url": "https://techcrunch.com/2026/06/25/netris-raises-15m-series-a-from-a16z-to-help-ai-neoclouds-go-live-faster/", "theme": "business", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 404170, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/25/netris-raises-15m-series-a-from-a16z-to-help-ai-neoclouds-go-live-faster/"}], "sum": "Netris has secured $15 million in Series A funding from Andreessen Horowitz to enhance its network automation platform for neoclouds, which are data centers optimized for AI workloads. This funding will enable Netris to accelerate its development and expand its team, addressing the critical need for faster deployment of cloud services in a competitive AI landscape. The company's technology promises to reduce the time and complexity involved in setting up data centers, which is crucial as demand for AI infrastructure grows."}, {"title": "Adobe acquires image and video enhancement tool maker Topaz Labs", "detail": "n/f2d00f06e04a.html", "url": "https://techcrunch.com/2026/06/25/adobe-acquires-image-and-video-enhancement-tool-maker-topaz-labs/", "theme": "business", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 409308, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/25/adobe-acquires-image-and-video-enhancement-tool-maker-topaz-labs/"}], "sum": "Adobe has announced its acquisition of Topaz Labs, a company known for its AI-driven image and video enhancement tools. This acquisition aims to integrate Topaz's technology into Adobe's Creative Cloud suite, enhancing its offerings against competitors like Canva and Blackmagic Design. The move is significant as it allows Adobe to provide faster and more efficient AI capabilities, potentially retaining users within its ecosystem and improving its competitive edge in the creative software market."}, {"title": "Europe is pushing back on Washington’s chip war", "detail": "n/7be3aa61f2a7.html", "url": "https://techcrunch.com/2026/06/24/europe-is-pushing-back-on-washingtons-chip-war/", "theme": "business", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 457392, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/24/europe-is-pushing-back-on-washingtons-chip-war/"}], "sum": "The Dutch Trade Minister visited Washington to express opposition to the MATCH Act, which would restrict Chinese access to Western semiconductor equipment, significantly impacting ASML, Europe's leading chipmaker. This legislation could jeopardize ASML's sales, as China represents 19% of its revenue. The situation highlights the tension between U.S. and European interests in the semiconductor industry, with potential implications for global supply chains and technology access."}, {"title": "Cerebras stock plunges after earnings as CEO says margin outlook was misunderstood", "detail": "n/3e68bacc7cf1.html", "url": "https://techcrunch.com/2026/06/24/cerebras-stock-plunges-after-earnings-as-ceo-says-margin-outlook-was-misunderstood/", "theme": "business", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 462607, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/24/cerebras-stock-plunges-after-earnings-as-ceo-says-margin-outlook-was-misunderstood/"}], "sum": "Cerebras Systems' stock fell nearly 20% following its first earnings report since going public, despite exceeding revenue expectations. The decline was attributed to a revised gross margin forecast of 38% to 41%, down from 47% in the previous quarter. This situation highlights the market's sensitivity to margin guidance and the potential impact of operational decisions on investor confidence."}, {"title": "Read this before you vibe-code another app", "detail": "n/d42e17779ae0.html", "url": "https://www.theverge.com/ai-artificial-intelligence/950844/vibe-coding-security-risks-apps", "theme": "insights", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 677508, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/950844/vibe-coding-security-risks-apps"}], "sum": "The rise of vibe coding, where individuals use AI to create apps quickly, has led to significant security vulnerabilities. Many amateur developers overlook critical security measures, resulting in apps that expose sensitive data. This trend poses risks not only for personal projects but also for applications that handle sensitive information, highlighting the need for heightened security awareness and practices among casual coders."}, {"title": "Scientists Found A Better Language For AI Agents", "detail": "n/59801fd3376e.html", "url": "https://www.youtube.com/watch?v=dUmT0OIGoqE", "theme": "models", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 925548, "urls": [{"label": "Two Minute Papers", "href": "https://www.youtube.com/watch?v=dUmT0OIGoqE"}], "sum": "Researchers have proposed a new communication method for AI agents that bypasses traditional language, allowing them to exchange raw numerical data directly. This approach has shown to improve performance on complex tasks significantly, with a reported accuracy increase from 73% to 86% on competition-level math problems. The implications are substantial, as this could enable smaller AI models to compete with larger, more expensive systems, potentially reducing costs and improving efficiency in AI applications."}, {"title": "Qualcomm’s latest chip hints that more powerful smart glasses could be on the way", "detail": "n/350c6ceab2a9.html", "url": "https://www.theverge.com/gadgets/950229/qualcomm-snapdragon-reality-elite-xr-smart-glasses-wearables", "theme": "models", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 1174308, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/gadgets/950229/qualcomm-snapdragon-reality-elite-xr-smart-glasses-wearables"}], "sum": "Qualcomm has unveiled the Snapdragon Reality Elite chip, set to enhance smart glasses like Xreal’s Project Aura. This chip features significant performance upgrades, including a 60% increase in GPU performance and improved battery life. These advancements are crucial as they address current limitations in smart glasses, potentially leading to more efficient and capable wearable devices in the near future."}, {"title": "Skydio CEO Adam Bry on why Silicon Valley shouldn’t draw red lines for drone use", "detail": "n/f3e37047d492.html", "url": "https://www.theverge.com/podcast/949195/skydio-ceo-adam-bry-autonmous-drones-china-red-lines-military", "theme": "insights", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 1271508, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/podcast/949195/skydio-ceo-adam-bry-autonmous-drones-china-red-lines-military"}], "sum": "Skydio CEO Adam Bry discusses the company's focus on the enterprise market for autonomous drones, particularly in sectors like public safety and utilities. The recent ban on foreign-made drones has positioned Skydio as a leading US manufacturer, filling a significant gap left by competitors. This shift highlights the growing importance of domestic drone production and the potential for AI integration in critical industries, which could reshape operational efficiencies and safety protocols."}, {"title": "Andrew Yang thinks the next big startup opportunity is lowering the cost of living", "detail": "n/d5a167a79f01.html", "url": "https://techcrunch.com/2026/06/12/andrew-yang-thinks-the-next-big-startup-opportunity-is-lowering-the-cost-of-living/", "theme": "insights", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 1479449, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/12/andrew-yang-thinks-the-next-big-startup-opportunity-is-lowering-the-cost-of-living/"}], "sum": "Andrew Yang proposes that the next startup wave should focus on reducing living costs rather than extracting money from consumers. He cites examples like Noble Mobile, which offers lower cell service costs and shares profits with users, as part of a new business model aimed at addressing economic pressures exacerbated by AI. This approach could appeal to consumers seeking financial relief, but attracting investment may be challenging due to current capital concentration in AI-focused ventures."}, {"title": "Theker just raised $85M to build the factory robot that doesn’t specialize in anything", "detail": "n/b612f2b2ad9c.html", "url": "https://techcrunch.com/2026/06/11/theker-just-raised-85m-to-build-the-factory-robot-that-doesnt-specialize-in-anything/", "theme": "business", "score": 67, "level": "medium", "sources": 1, "players": [], "ago": 1574621, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/11/cheaper-faster-and-culturally-aware-avataars-video-ai-is-built-for-indias-scale/"}], "sum": "Theker has secured $85 million in funding to develop a versatile factory robot that is not limited to a single task. This investment highlights a growing trend towards automation solutions that can adapt to various manufacturing processes. The implications for manufacturers include potential cost savings and increased efficiency, as such robots could reduce the need for specialized machinery."}, {"title": "AI inference startup Baseten reportedly raising $1.5B months after its last mega-round", "detail": "n/3d5da6d1201a.html", "url": "https://techcrunch.com/2026/06/18/ai-inference-startup-baseten-reportedly-raising-1-5b-months-after-its-last-mega-round/", "theme": "business", "score": 66, "level": "high", "sources": 1, "players": [], "ago": 985895, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/21/when-the-trump-administration-cracks-down-on-anthropic-who-benefits/"}], "sum": "Baseten, an AI inference startup, is nearing a $1.5 billion funding round, significantly increasing its valuation from $5 billion to $13 billion in just five months. This rapid growth highlights the intense investor interest in AI inference technologies, which are critical for optimizing model performance and cost efficiency. The split-priced nature of the round raises questions about valuation practices in the startup ecosystem, potentially impacting investor confidence and future funding strategies."}, {"title": "Plaud reports over $100M in ARR after selling 2M AI notetakers", "detail": "n/b934c02448b6.html", "url": "https://techcrunch.com/2026/06/16/plaud-says-its-software-business-topped-100m-in-arr-after-shipping-over-2m-ai-notetakers/", "theme": "business", "score": 66, "level": "medium", "sources": 1, "players": [], "ago": 1181508, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/16/plaud-says-its-software-business-topped-100m-in-arr-after-shipping-over-2m-ai-notetakers/"}], "sum": "Plaud has achieved over $100 million in annual recurring revenue (ARR) following the sale of more than 2 million AI-powered notetakers. This growth highlights a shift in the AI market, where Plaud's hardware approach contrasts with the prevalent software-centric models. The company's success suggests a potential demand for innovative hardware solutions that enhance real-life interactions, which could influence future product development in the AI space."}, {"title": "Arena, the AI leaderboard everyone uses, is now a $100M business", "detail": "n/84554f2bc1eb.html", "url": "https://techcrunch.com/2026/06/29/arena-the-ai-leaderboard-everyone-uses-is-now-a-100m-business/", "theme": "business", "score": 65, "level": "high", "sources": 1, "players": [], "ago": 48751, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/29/arena-the-ai-leaderboard-everyone-uses-is-now-a-100m-business/"}], "sum": "Arena, an AI leaderboard platform that originated from UC Berkeley, has achieved an annualized run-rate revenue of $100 million just eight months after launching its commercial service. This growth is attributed to its crowdsourced model performance evaluations, which have attracted significant user engagement. The company's ability to monetize its platform through AI Evaluations indicates a strong market demand for performance analytics in AI development, positioning Arena as a key player in the AI evaluation space."}, {"title": "Suno launches Spark incubator program to feed independent artists to its AI machine", "detail": "n/c09e447fce12.html", "url": "https://www.theverge.com/ai-artificial-intelligence/958801/suno-launches-spark-incubator-program-to-feed-independent-artists-to-its-ai-machine", "theme": "business", "score": 65, "level": "medium", "sources": 1, "players": [], "ago": 125052, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/958801/suno-launches-spark-incubator-program-to-feed-independent-artists-to-its-ai-machine"}], "sum": "Suno has introduced the Spark incubator program aimed at supporting independent artists through grants, mentorship, and marketing assistance. However, the program's terms have raised concerns, particularly regarding the extensive rights Suno claims over artists' works and a non-disparagement clause that limits artists' ability to speak negatively about the company. This raises significant implications for artists' autonomy and rights in the evolving landscape of AI-generated content."}, {"title": "Apple Vision Pro exec is reportedly leaving for OpenAI", "detail": "n/307bfc45e28b.html", "url": "https://techcrunch.com/2026/06/27/apple-vision-pro-exec-is-reportedly-leaving-for-openai/", "theme": "business", "score": 65, "level": "medium", "sources": 1, "players": ["OpenAI", "Apple"], "ago": 224799, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/27/apple-vision-pro-exec-is-reportedly-leaving-for-openai/"}], "sum": "Paul Meade, Apple’s VP overseeing the Vision Pro headset, is leaving to join OpenAI’s hardware team. This transition comes amid internal changes at Apple as John Ternus prepares to become CEO, potentially impacting the company's hardware strategy. Meade's departure raises questions about Apple's future in the competitive wearable market, especially as it aims to launch more affordable smart glasses to rival Meta's offerings."}, {"title": "The next humanoid robot might not look human at all", "detail": "n/90b0dc3d74ad.html", "url": "https://www.theverge.com/ai-artificial-intelligence/951283/genesis-ai-humanoid-robot-eno", "theme": "other", "score": 65, "level": "medium", "sources": 1, "players": [], "ago": 1113892, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/951283/genesis-ai-humanoid-robot-eno"}], "sum": "Genesis AI, a French startup backed by Eric Schmidt, has unveiled Eno, a humanoid robot designed for functionality rather than human-like appearance. Eno's design focuses on human capabilities, featuring hands that mimic human dexterity. This approach could redefine the role of humanoid robots in various sectors, with production slated to begin by the end of 2026, targeting industries such as manufacturing and healthcare."}, {"title": "Cursor launches mobile app for coding agents", "detail": "n/9665bc4af006.html", "url": "https://techcrunch.com/2026/06/29/cursor-now-has-a-mobile-app-for-guiding-your-coding-agent-on-the-go/", "theme": "tools", "score": 62, "level": "medium", "sources": 1, "players": [], "ago": 50878, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/29/cursor-now-has-a-mobile-app-for-guiding-your-coding-agent-on-the-go/"}], "sum": "Cursor has launched a mobile app for iOS that allows users to interact with coding agents directly from their phones. This development aligns with the company's shift towards independent coding agents, as seen in the Cursor 2.0 updates. The move to mobile reflects a broader trend in AI coding tools, enabling developers to manage coding tasks more flexibly, which could lead to a significant change in how coding is approached in the industry."}, {"title": "SoftBank’s CEO questions Elon Musk’s orbital data center vision", "detail": "n/ab24e3be6fc2.html", "url": "https://techcrunch.com/2026/06/27/softbanks-ceo-isnt-the-only-one-with-questions-about-elon-musks-orbital-data-center-hype/", "theme": "business", "score": 62, "level": "medium", "sources": 1, "players": ["SpaceX"], "ago": 210552, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/27/softbanks-ceo-isnt-the-only-one-with-questions-about-elon-musks-orbital-data-center-hype/"}], "sum": "Masayoshi Son, CEO of SoftBank, expressed skepticism about Elon Musk's proposal for orbital data centers, arguing they won't significantly reduce costs and will take too long to develop. This skepticism highlights the urgency in the AI sector, where immediate solutions are needed rather than long-term speculative projects. Son's remarks could influence investor confidence and the direction of funding in space-based data initiatives, as stakeholders reassess the viability of such ambitious projects."}, {"title": "Signal’s Meredith Whittaker warns against trusting AI chatbots", "detail": "n/a8b7179eed63.html", "url": "https://techcrunch.com/2026/06/20/signals-meredith-whittaker-wants-you-to-remember-that-ai-chatbots-are-not-your-friends/", "theme": "insights", "score": 62, "level": "medium", "sources": 1, "players": [], "ago": 815959, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/20/signals-meredith-whittaker-wants-you-to-remember-that-ai-chatbots-are-not-your-friends/"}], "sum": "Meredith Whittaker, President of Signal, emphasized the privacy risks associated with AI chatbots like ChatGPT and Microsoft Copilot, stating they are not sentient and should not be considered friends. She highlighted the dangers of these systems having pervasive access to personal information, which could lead to significant privacy breaches. This perspective is crucial for users and organizations to understand the limitations and risks of relying on AI tools for personal and sensitive tasks."}, {"title": "In the Weights: Your New AI-Centric Vanity Search", "detail": "n/af08cad5eb0b.html", "url": "https://techcrunch.com/2026/06/20/in-the-weights-is-your-new-ai-centric-vanity-search/", "theme": "tools", "score": 62, "level": "medium", "sources": 1, "players": [], "ago": 819037, "urls": [{"label": "TechCrunch AI", "href": "https://techcrunch.com/2026/06/20/in-the-weights-is-your-new-ai-centric-vanity-search/"}], "sum": "In the Weights is a new website that allows users to gauge their significance in AI models by querying various AI systems about themselves. This tool reflects a shift in how individuals perceive their online presence, moving from traditional search engines to AI-driven assessments. The implications for users include a new metric for personal branding and visibility in an increasingly AI-centric world, potentially influencing how individuals manage their online identities."}, {"title": "AI search grounded in Facebook posts? What could go wrong?", "detail": "n/c80a0f3b9e4a.html", "url": "https://www.theverge.com/ai-artificial-intelligence/951099/meta-ai-mode-search-hands-on", "theme": "features", "score": 62, "level": "medium", "sources": 1, "players": ["Meta"], "ago": 1100508, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/951099/meta-ai-mode-search-hands-on"}], "sum": "Meta has introduced AI Mode in its search feature on Facebook, designed to provide users with recommendations based on public posts from its platforms. While it has potential utility for planning activities, the reliance on user-generated content raises concerns about misinformation and accuracy. Users may encounter unreliable suggestions, which could undermine trust in the tool and affect its adoption."}, {"title": "Midjourney's Shift to Medical Imaging Raises Concerns", "detail": "n/1e27aee6505e.html", "url": "https://www.theverge.com/report/954826/midjourney-medical-ai-ultrasound-body-scanner-lacks-evidence", "theme": "business", "score": 55, "level": "medium", "sources": 1, "players": [], "ago": 573313, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/report/954826/midjourney-medical-ai-ultrasound-body-scanner-lacks-evidence"}], "sum": "Midjourney, known for its AI image generation, has announced a pivot to medical imaging with a new ultrasound scanner that aims to rival MRI technology. However, experts express skepticism regarding the lack of public evidence supporting the effectiveness of this new device. This development matters as it highlights the challenges startups face when entering the medical field, particularly in gaining credibility and regulatory approval."}, {"title": "OpenAI is teasing new hardware… for Codex", "detail": "n/811accb0367a.html", "url": "https://www.theverge.com/ai-artificial-intelligence/959174/openai-codex-hardware-work-louder", "theme": "tools", "score": 45, "level": "low", "sources": 1, "players": ["OpenAI"], "ago": 44385, "urls": [{"label": "The Verge AI", "href": "https://www.theverge.com/ai-artificial-intelligence/959174/openai-codex-hardware-work-louder"}], "sum": "OpenAI is set to launch a new device for its Codex AI coding tool on July 15, developed in collaboration with Work Louder. The device appears to be a macro pad designed to enhance user interaction with Codex by allowing customizable shortcuts. This launch is significant as it indicates OpenAI's continued investment in hardware to improve user experience, potentially expanding Codex's adoption among developers."}]};
